+const std = @import("std");
+
+/// Memory pressure levels
+pub const MemoryPressure = enum {
+    low, // < 70% usage, can grow context
+    medium, // 70-85% usage, maintain current
+    high, // > 85% usage, should shrink
+    critical, // > 95% usage, emergency shrink
+
+    pub fn toString(self: MemoryPressure) []const u8 {
+        return switch (self) {
+            .low => "low",
+            .medium => "medium",
+            .high => "high",
+            .critical => "critical",
+        };
+    }
+};
+
+/// Memory statistics
+pub const MemoryStats = struct {
+    total_gb: f64,
+    used_gb: f64,
+    available_gb: f64,
+    usage_percent: f64,
+    pressure: MemoryPressure,
+
+    pub fn format(
+        self: MemoryStats,
+        comptime fmt: []const u8,
+        options: std.fmt.FormatOptions,
+        writer: anytype,
+    ) !void {
+        _ = fmt;
+        _ = options;
+        try writer.print("MemoryStats{{ total={d:.1}GB, used={d:.1}GB, available={d:.1}GB, usage={d:.1}%, pressure={s} }}", .{
+            self.total_gb,
+            self.used_gb,
+            self.available_gb,
+            self.usage_percent,
+            self.pressure.toString(),
+        });
+    }
+};
+
+/// System memory monitor with configurable thresholds
+pub const MemoryMonitor = struct {
+    allocator: std.mem.Allocator,
+    system_total_gb: f64,
+    threshold_warning: f64, // Default: 70% usage
+    threshold_critical: f64, // Default: 85% usage
+    threshold_emergency: f64, // Default: 95% usage
+    last_check: i64,
+    check_interval_ms: i64, // Poll interval in milliseconds
+    cached_stats: ?MemoryStats,
+
+    pub fn init(allocator: std.mem.Allocator) !MemoryMonitor {
+        const total_memory = try getTotalSystemMemory();
+
+        return MemoryMonitor{
+            .allocator = allocator,
+            .system_total_gb = @as(f64, @floatFromInt(total_memory)) / (1024.0 * 1024.0 * 1024.0),
+            .threshold_warning = 0.70,
+            .threshold_critical = 0.85,
+            .threshold_emergency = 0.95,
+            .last_check = 0,
+            .check_interval_ms = 100, // Check every 100ms
+            .cached_stats = null,
+        };
+    }
+
+    pub fn deinit(self: *MemoryMonitor) void {
+        _ = self;
+        // No cleanup needed currently
+    }
+
+    /// Get current memory pressure level
+    pub fn getCurrentPressure(self: *MemoryMonitor) !MemoryPressure {
+        const stats = try self.getStats();
+        return stats.pressure;
+    }
+
+    /// Get detailed memory statistics (cached with interval)
+    pub fn getStats(self: *MemoryMonitor) !MemoryStats {
+        const now = std.time.milliTimestamp();
+
+        // Return cached stats if within interval
+        if (self.cached_stats) |cached| {
+            if ((now - self.last_check) < self.check_interval_ms) {
+                return cached;
+            }
+        }
+
+        // Update stats
+        const stats = try self.querySystemMemory();
+        self.cached_stats = stats;
+        self.last_check = now;
+
+        return stats;
+    }
+
+    /// Force refresh of memory statistics
+    pub fn refreshStats(self: *MemoryMonitor) !MemoryStats {
+        const stats = try self.querySystemMemory();
+        self.cached_stats = stats;
+        self.last_check = std.time.milliTimestamp();
+        return stats;
+    }
+
+    /// Query system memory from OS
+    fn querySystemMemory(self: *MemoryMonitor) !MemoryStats {
+        const used_memory = try getUsedSystemMemory();
+        const used_gb = @as(f64, @floatFromInt(used_memory)) / (1024.0 * 1024.0 * 1024.0);
+        const available_gb = self.system_total_gb - used_gb;
+        const usage_percent = (used_gb / self.system_total_gb) * 100.0;
+
+        // Determine pressure level
+        const usage_ratio = used_gb / self.system_total_gb;
+        const pressure = if (usage_ratio >= self.threshold_emergency)
+            MemoryPressure.critical
+        else if (usage_ratio >= self.threshold_critical)
+            MemoryPressure.high
+        else if (usage_ratio >= self.threshold_warning)
+            MemoryPressure.medium
+        else
+            MemoryPressure.low;
+
+        return MemoryStats{
+            .total_gb = self.system_total_gb,
+            .used_gb = used_gb,
+            .available_gb = available_gb,
+            .usage_percent = usage_percent,
+            .pressure = pressure,
+        };
+    }
+
+    /// Check if safe to grow context
+    pub fn canGrowContext(self: *MemoryMonitor, estimated_growth_gb: f64) !bool {
+        const stats = try self.getStats();
+
+        // Don't grow if pressure is high or critical
+        if (stats.pressure == .high or stats.pressure == .critical) {
+            return false;
+        }
+
+        // Check if we have enough headroom
+        const after_growth_gb = stats.used_gb + estimated_growth_gb;
+        const after_growth_ratio = after_growth_gb / stats.total_gb;
+
+        // Only allow growth if we stay below warning threshold
+        return after_growth_ratio < self.threshold_warning;
+    }
+
+    /// Check if should shrink context due to memory pressure
+    pub fn shouldShrinkContext(self: *MemoryMonitor) !bool {
+        const pressure = try self.getCurrentPressure();
+        return pressure == .high or pressure == .critical;
+    }
+};
+
+/// Platform-specific memory query functions
+
+/// Get total system memory in bytes
+fn getTotalSystemMemory() !u64 {
+    if (@import("builtin").os.tag == .macos) {
+        return try getTotalSystemMemoryMacOS();
+    } else if (@import("builtin").os.tag == .linux) {
+        return try getTotalSystemMemoryLinux();
+    } else {
+        // Fallback: assume 8GB
+        std.debug.print("Warning: Unknown platform, assuming 8GB RAM\n", .{});
+        return 8 * 1024 * 1024 * 1024;
+    }
+}
+
+/// Get used system memory in bytes
+fn getUsedSystemMemory() !u64 {
+    if (@import("builtin").os.tag == .macos) {
+        return try getUsedSystemMemoryMacOS();
+    } else if (@import("builtin").os.tag == .linux) {
+        return try getUsedSystemMemoryLinux();
+    } else {
+        // Fallback: assume 4GB used
+        std.debug.print("Warning: Unknown platform, assuming 4GB used\n", .{});
+        return 4 * 1024 * 1024 * 1024;
+    }
+}
+
+// ============================================================================
+// macOS Implementation
+// ============================================================================
+
+fn getTotalSystemMemoryMacOS() !u64 {
+    // Use sysctl to get physical memory
+    const std_c = @cImport({
+        @cInclude("sys/types.h");
+        @cInclude("sys/sysctl.h");
+    });
+
+    var size: usize = @sizeOf(u64);
+    var memsize: u64 = 0;
+
+    const name = [_]c_int{ std_c.CTL_HW, std_c.HW_MEMSIZE };
+    const result = std_c.sysctl(
+        &name,
+        name.len,
+        &memsize,
+        &size,
+        null,
+        0,
+    );
+
+    if (result != 0) {
+        return error.SysctlFailed;
+    }
+
+    return memsize;
+}
+
+fn getUsedSystemMemoryMacOS() !u64 {
+    // Use vm_stat to get memory usage
+    // For now, use a simpler approach with sysctl
+    const std_c = @cImport({
+        @cInclude("sys/types.h");
+        @cInclude("sys/sysctl.h");
+        @cInclude("mach/mach.h");
+        @cInclude("mach/vm_statistics.h");
+    });
+
+    var count: std_c.mach_msg_type_number_t = @divExact(
+        @sizeOf(std_c.vm_statistics64_data_t),
+        @sizeOf(c_int),
+    );
+    var stats: std_c.vm_statistics64_data_t = undefined;
+
+    const result = std_c.host_statistics64(
+        std_c.mach_host_self(),
+        std_c.HOST_VM_INFO64,
+        @as(*c_int, @ptrCast(&stats)),
+        &count,
+    );
+
+    if (result != std_c.KERN_SUCCESS) {
+        return error.HostStatisticsFailed;
+    }
+
+    // Calculate used memory
+    // active + wired + occupied = used memory
+    const page_size = std_c.vm_page_size;
+    const active_count: u64 = stats.active_count;
+    const wire_count: u64 = stats.wire_count;
+    const compressor_page_count: u64 = stats.compressor_page_count;
+
+    const used_pages = active_count + wire_count + compressor_page_count;
+    const used_bytes = used_pages * @as(u64, page_size);
+
+    return used_bytes;
+}
+
+// ============================================================================
+// Linux Implementation
+// ============================================================================
+
+fn getTotalSystemMemoryLinux() !u64 {
+    const file = try std.fs.openFileAbsolute("/proc/meminfo", .{});
+    defer file.close();
+
+    var buf_reader = std.io.bufferedReader(file.reader());
+    var in_stream = buf_reader.reader();
+
+    var buf: [256]u8 = undefined;
+    while (try in_stream.readUntilDelimiterOrEof(&buf, '\n')) |line| {
+        if (std.mem.startsWith(u8, line, "MemTotal:")) {
+            // Parse: "MemTotal:       16384000 kB"
+            var iter = std.mem.split(u8, line, " ");
+            _ = iter.next(); // Skip "MemTotal:"
+            while (iter.next()) |part| {
+                if (part.len == 0) continue;
+                if (std.mem.eql(u8, part, "kB")) break;
+
+                const kb = try std.fmt.parseInt(u64, part, 10);
+                return kb * 1024; // Convert kB to bytes
+            }
+        }
+    }
+
+    return error.MemInfoParseFailed;
+}
+
+fn getUsedSystemMemoryLinux() !u64 {
+    const file = try std.fs.openFileAbsolute("/proc/meminfo", .{});
+    defer file.close();
+
+    var buf_reader = std.io.bufferedReader(file.reader());
+    var in_stream = buf_reader.reader();
+
+    var mem_total: ?u64 = null;
+    var mem_available: ?u64 = null;
+
+    var buf: [256]u8 = undefined;
+    while (try in_stream.readUntilDelimiterOrEof(&buf, '\n')) |line| {
+        if (std.mem.startsWith(u8, line, "MemTotal:")) {
+            mem_total = try parseMemInfoLine(line);
+        } else if (std.mem.startsWith(u8, line, "MemAvailable:")) {
+            mem_available = try parseMemInfoLine(line);
+        }
+
+        if (mem_total != null and mem_available != null) {
+            break;
+        }
+    }
+
+    if (mem_total == null or mem_available == null) {
+        return error.MemInfoParseFailed;
+    }
+
+    const used_kb = mem_total.? - mem_available.?;
+    return used_kb * 1024; // Convert kB to bytes
+}
+
+fn parseMemInfoLine(line: []const u8) !u64 {
+    var iter = std.mem.split(u8, line, " ");
+    _ = iter.next(); // Skip label
+    while (iter.next()) |part| {
+        if (part.len == 0) continue;
+        if (std.mem.eql(u8, part, "kB")) break;
+        return try std.fmt.parseInt(u64, part, 10);
+    }
+    return error.ParseFailed;
+}
+
+// Tests
+test "memory pressure enum" {
+    try std.testing.expect(MemoryPressure.low != MemoryPressure.high);
+    try std.testing.expectEqualStrings("low", MemoryPressure.low.toString());
+    try std.testing.expectEqualStrings("critical", MemoryPressure.critical.toString());
+}
+
+test "memory monitor init" {
+    const allocator = std.testing.allocator;
+    var monitor = try MemoryMonitor.init(allocator);
+    defer monitor.deinit();
+
+    try std.testing.expect(monitor.system_total_gb > 0);
+    try std.testing.expectEqual(@as(f64, 0.70), monitor.threshold_warning);
+    try std.testing.expectEqual(@as(f64, 0.85), monitor.threshold_critical);
+}
